# solution.py
"""NewsCollab / Team Collaboration Manager.

A self-contained, thread-safe, in-memory backend for collaborative content
creation and team coordination. It manages users, projects, tasks, messages
(with attachments and threaded replies), peer ratings, performance dashboards,
and exportable reports (CSV / PDF).

Design notes
------------
* Standard library only, ASCII only.
* A single re-entrant lock guards all mutable state. Every public sub-manager
  exposes that same lock instance via ``_lock`` so callers can reason about a
  single, shared critical section.
* IDs are globally unique across every entity type (a single monotonic
  counter starting at 1).
* Read APIs return deep copies so callers cannot mutate internal state by
  holding on to a returned object.
"""

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional, Tuple


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    MEMBER = "member"
    ADMIN = "admin"
    MANAGER = "manager"
    VIEWER = "viewer"


class ReportFormat(Enum):
    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for all domain errors."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint is violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Entities
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]
    created_at: datetime


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    attachments: List[Attachment]
    created_at: datetime
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Shared state
# ---------------------------------------------------------------------------
class _State:
    """Central, lock-guarded data store shared by every sub-manager."""

    def __init__(self, now: Callable[[], datetime]):
        self.lock = threading.RLock()
        self.now = now
        self._id_counter = 0

        # Primary stores keyed by global id.
        self.users: Dict[int, User] = {}
        self.projects: Dict[int, Project] = {}
        self.tasks: Dict[int, Task] = {}
        self.messages: Dict[int, Message] = {}
        self.ratings: Dict[int, Rating] = {}

        # Uniqueness indexes.
        self.username_to_id: Dict[str, int] = {}
        self.email_to_id: Dict[str, int] = {}

        # Secondary lookup indexes (id -> set of ids).
        self.tasks_by_project: Dict[int, set] = {}
        self.tasks_by_assignee: Dict[int, set] = {}
        self.messages_by_project: Dict[int, set] = {}
        self.messages_by_task: Dict[int, set] = {}
        self.ratings_by_ratee: Dict[int, set] = {}

    def next_id(self) -> int:
        self._id_counter += 1
        return self._id_counter

    # -- index helpers ----------------------------------------------------
    def index_task(self, task: Task) -> None:
        self.tasks_by_project.setdefault(task.project_id, set()).add(task.id)
        if task.assignee_id is not None:
            self.tasks_by_assignee.setdefault(task.assignee_id, set()).add(task.id)

    def set_task_assignee(self, task: Task, new_assignee: Optional[int]) -> None:
        if task.assignee_id is not None:
            bucket = self.tasks_by_assignee.get(task.assignee_id)
            if bucket is not None:
                bucket.discard(task.id)
        task.assignee_id = new_assignee
        if new_assignee is not None:
            self.tasks_by_assignee.setdefault(new_assignee, set()).add(task.id)

    def deindex_task(self, task: Task) -> None:
        bucket = self.tasks_by_project.get(task.project_id)
        if bucket is not None:
            bucket.discard(task.id)
        if task.assignee_id is not None:
            abucket = self.tasks_by_assignee.get(task.assignee_id)
            if abucket is not None:
                abucket.discard(task.id)

    def index_message(self, message: Message) -> None:
        if message.project_id is not None:
            self.messages_by_project.setdefault(message.project_id, set()).add(message.id)
        if message.task_id is not None:
            self.messages_by_task.setdefault(message.task_id, set()).add(message.id)

    def deindex_message(self, message: Message) -> None:
        if message.project_id is not None:
            bucket = self.messages_by_project.get(message.project_id)
            if bucket is not None:
                bucket.discard(message.id)
        if message.task_id is not None:
            bucket = self.messages_by_task.get(message.task_id)
            if bucket is not None:
                bucket.discard(message.id)


def _clone(obj):
    """Return a deep copy so callers cannot mutate stored state."""
    return copy.deepcopy(obj)


def _clone_list(seq):
    return [copy.deepcopy(item) for item in seq]


# ---------------------------------------------------------------------------
# Base manager with shared lookups
# ---------------------------------------------------------------------------
class _BaseManager:
    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock

    # The following helpers assume the caller already holds the lock.
    def _require_user(self, user_id: int) -> User:
        user = self._state.users.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def _require_project(self, project_id: int) -> Project:
        project = self._state.projects.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id: int) -> Task:
        task = self._state.tasks.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id: int) -> Message:
        message = self._state.messages.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message


# ---------------------------------------------------------------------------
# User management
# ---------------------------------------------------------------------------
class UserManager(_BaseManager):
    @staticmethod
    def _validate_email(email: str) -> str:
        if not isinstance(email, str):
            raise ValidationError("email must be a string")
        cleaned = email.strip()
        if not cleaned or "@" not in cleaned:
            raise ValidationError("invalid email address")
        return cleaned

    @staticmethod
    def _validate_username(username: str) -> str:
        if not isinstance(username, str):
            raise ValidationError("username must be a string")
        cleaned = username.strip()
        if not cleaned:
            raise ValidationError("username must not be empty")
        return cleaned

    def register_user(self, username, email, role=UserRole.MEMBER) -> User:
        with self._lock:
            uname = self._validate_username(username)
            cleaned_email = self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if uname in self._state.username_to_id:
                raise DuplicateError("username already in use")
            if cleaned_email in self._state.email_to_id:
                raise DuplicateError("email already in use")

            user = User(
                id=self._state.next_id(),
                username=uname,
                email=cleaned_email,
                role=role,
                created_at=self._state.now(),
            )
            self._state.users[user.id] = user
            self._state.username_to_id[uname] = user.id
            self._state.email_to_id[cleaned_email] = user.id
            return _clone(user)

    def get_user(self, user_id) -> User:
        with self._lock:
            return _clone(self._require_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            ordered = [self._state.users[i] for i in sorted(self._state.users)]
            return _clone_list(ordered)

    def update_user(self, user_id, username=None, email=None, role=None) -> User:
        with self._lock:
            user = self._require_user(user_id)

            new_username = user.username
            if username is not None:
                new_username = self._validate_username(username)
                existing = self._state.username_to_id.get(new_username)
                if existing is not None and existing != user.id:
                    raise DuplicateError("username already in use")

            new_email = user.email
            if email is not None:
                new_email = self._validate_email(email)
                existing = self._state.email_to_id.get(new_email)
                if existing is not None and existing != user.id:
                    raise DuplicateError("email already in use")

            new_role = user.role
            if role is not None:
                if not isinstance(role, UserRole):
                    raise ValidationError("role must be a UserRole")
                new_role = role

            # Apply, keeping uniqueness indexes consistent.
            if new_username != user.username:
                self._state.username_to_id.pop(user.username, None)
                self._state.username_to_id[new_username] = user.id
                user.username = new_username
            if new_email != user.email:
                self._state.email_to_id.pop(user.email, None)
                self._state.email_to_id[new_email] = user.id
                user.email = new_email
            user.role = new_role
            return _clone(user)

    def delete_user(self, user_id) -> None:
        with self._lock:
            user = self._require_user(user_id)

            for project in self._state.projects.values():
                if project.owner_id == user.id:
                    raise ConflictError("user owns one or more projects")

            assigned = self._state.tasks_by_assignee.get(user.id, set())
            for task_id in assigned:
                task = self._state.tasks.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open tasks assigned")

            # Detach from any completed tasks then remove.
            for task_id in list(assigned):
                task = self._state.tasks.get(task_id)
                if task is not None:
                    task.assignee_id = None
            self._state.tasks_by_assignee.pop(user.id, None)

            self._state.username_to_id.pop(user.username, None)
            self._state.email_to_id.pop(user.email, None)
            del self._state.users[user.id]


# ---------------------------------------------------------------------------
# Project management
# ---------------------------------------------------------------------------
class ProjectManager(_BaseManager):
    def create_project(self, name, start_date, end_date, owner_id, description="") -> Project:
        with self._lock:
            if not isinstance(name, str) or not name.strip():
                raise ValidationError("project name must not be empty")
            if end_date < start_date:
                raise ValidationError("end_date must not be before start_date")
            self._require_user(owner_id)

            project = Project(
                id=self._state.next_id(),
                name=name.strip(),
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._state.now(),
            )
            self._state.projects[project.id] = project
            return _clone(project)

    def get_project(self, project_id) -> Project:
        with self._lock:
            return _clone(self._require_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            ordered = [self._state.projects[i] for i in sorted(self._state.projects)]
            return _clone_list(ordered)

    def update_project(self, project_id, name=None, start_date=None,
                       end_date=None, description=None) -> Project:
        with self._lock:
            project = self._require_project(project_id)

            new_name = project.name
            if name is not None:
                if not isinstance(name, str) or not name.strip():
                    raise ValidationError("project name must not be empty")
                new_name = name.strip()

            new_start = project.start_date if start_date is None else start_date
            new_end = project.end_date if end_date is None else end_date
            if new_end < new_start:
                raise ValidationError("end_date must not be before start_date")

            project.name = new_name
            project.start_date = new_start
            project.end_date = new_end
            if description is not None:
                project.description = description
            return _clone(project)

    def delete_project(self, project_id) -> None:
        with self._lock:
            project = self._require_project(project_id)

            # Cascade tasks (and their messages / assignee index entries).
            task_ids = list(self._state.tasks_by_project.get(project.id, set()))
            for task_id in task_ids:
                task = self._state.tasks.get(task_id)
                if task is None:
                    continue
                msg_ids = list(self._state.messages_by_task.get(task_id, set()))
                for msg_id in msg_ids:
                    message = self._state.messages.get(msg_id)
                    if message is not None:
                        self._state.deindex_message(message)
                        del self._state.messages[msg_id]
                self._state.messages_by_task.pop(task_id, None)
                self._state.deindex_task(task)
                del self._state.tasks[task_id]
            self._state.tasks_by_project.pop(project.id, None)

            # Cascade project-level messages.
            msg_ids = list(self._state.messages_by_project.get(project.id, set()))
            for msg_id in msg_ids:
                message = self._state.messages.get(msg_id)
                if message is not None:
                    self._state.deindex_message(message)
                    del self._state.messages[msg_id]
            self._state.messages_by_project.pop(project.id, None)

            del self._state.projects[project.id]


# ---------------------------------------------------------------------------
# Task management
# ---------------------------------------------------------------------------
class TaskManager(_BaseManager):
    def create_task(self, project_id, title, assignee_id=None, deadline=None) -> Task:
        with self._lock:
            project = self._require_project(project_id)
            if not isinstance(title, str) or not title.strip():
                raise ValidationError("task title must not be empty")
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline must not be before project start")
            if assignee_id is not None:
                self._require_user(assignee_id)

            task = Task(
                id=self._state.next_id(),
                project_id=project_id,
                title=title.strip(),
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._state.now(),
            )
            self._state.tasks[task.id] = task
            self._state.index_task(task)
            return _clone(task)

    def get_task(self, task_id) -> Task:
        with self._lock:
            return _clone(self._require_task(task_id))

    def list_tasks_by_project(self, project_id) -> List[Task]:
        with self._lock:
            self._require_project(project_id)
            ids = sorted(self._state.tasks_by_project.get(project_id, set()))
            return _clone_list([self._state.tasks[i] for i in ids])

    def list_tasks_by_assignee(self, user_id) -> List[Task]:
        with self._lock:
            self._require_user(user_id)
            ids = sorted(self._state.tasks_by_assignee.get(user_id, set()))
            return _clone_list([self._state.tasks[i] for i in ids])

    def assign_task(self, task_id, assignee_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            self._state.set_task_assignee(task, assignee_id)
            return _clone(task)

    def reassign_task(self, task_id, new_assignee_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            self._state.set_task_assignee(task, new_assignee_id)
            return _clone(task)

    def unassign_task(self, task_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._state.set_task_assignee(task, None)
            return _clone(task)

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self._state.projects.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline must not be before project start")
            task.deadline = deadline
            return _clone(task)

    def update_status(self, task_id, status) -> Task:
        with self._lock:
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            task = self._require_task(task_id)
            now = self._state.now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            task.status = status
            return _clone(task)


# ---------------------------------------------------------------------------
# Messaging
# ---------------------------------------------------------------------------
class MessageManager(_BaseManager):
    def post_message(self, author_id, body, project_id=None, task_id=None,
                     parent_id=None, attachments=None) -> Message:
        with self._lock:
            self._require_user(author_id)

            if project_id is None and task_id is None:
                raise ValidationError("message must target a project or a task")
            if project_id is not None and task_id is not None:
                raise ValidationError("message must target exactly one of project/task")
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)
            if parent_id is not None:
                self._require_message(parent_id)

            attachment_objs = self._build_attachments(attachments, author_id)
            text = body if isinstance(body, str) else ""
            if not text.strip() and not attachment_objs:
                raise ValidationError("message body must not be empty")

            message = Message(
                id=self._state.next_id(),
                author_id=author_id,
                body=text,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=attachment_objs,
                created_at=self._state.now(),
                edited_at=None,
            )
            self._state.messages[message.id] = message
            self._state.index_message(message)
            return _clone(message)

    def _build_attachments(self, attachments, author_id) -> List[Attachment]:
        result: List[Attachment] = []
        if not attachments:
            return result
        now = self._state.now()
        for item in attachments:
            filename, data = item
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("attachment filename must not be empty")
            size = len(data) if data is not None else 0
            result.append(
                Attachment(
                    filename=filename,
                    size=size,
                    uploaded_by=author_id,
                    uploaded_at=now,
                )
            )
        return result

    def edit_message(self, message_id, editor_id, new_body) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit this message")
            text = new_body if isinstance(new_body, str) else ""
            if not text.strip() and not message.attachments:
                raise ValidationError("message body must not be empty")
            message.body = text
            message.edited_at = self._state.now()
            return _clone(message)

    def add_attachment(self, message_id, uploader_id, filename, data) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError("only the author may add attachments")
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("attachment filename must not be empty")
            size = len(data) if data is not None else 0
            message.attachments.append(
                Attachment(
                    filename=filename,
                    size=size,
                    uploaded_by=uploader_id,
                    uploaded_at=self._state.now(),
                )
            )
            return _clone(message)

    def list_messages_by_project(self, project_id) -> List[Message]:
        with self._lock:
            self._require_project(project_id)
            ids = sorted(self._state.messages_by_project.get(project_id, set()))
            return _clone_list([self._state.messages[i] for i in ids])

    def list_messages_by_task(self, task_id) -> List[Message]:
        with self._lock:
            self._require_task(task_id)
            ids = sorted(self._state.messages_by_task.get(task_id, set()))
            return _clone_list([self._state.messages[i] for i in ids])

    def delete_message(self, message_id, requester_id) -> None:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError("only the author may delete this message")
            self._state.deindex_message(message)
            del self._state.messages[message.id]


# ---------------------------------------------------------------------------
# Performance dashboard
# ---------------------------------------------------------------------------
class PerformanceManager(_BaseManager):
    def _user_tasks(self, user_id) -> List[Task]:
        ids = self._state.tasks_by_assignee.get(user_id, set())
        return [self._state.tasks[i] for i in ids if i in self._state.tasks]

    @staticmethod
    def _completion_seconds(task: Task) -> Optional[float]:
        if (
            task.status == TaskStatus.COMPLETED
            and task.started_at is not None
            and task.completed_at is not None
        ):
            return (task.completed_at - task.started_at).total_seconds()
        return None

    def get_completion_rate(self, user_id) -> float:
        with self._lock:
            self._require_user(user_id)
            tasks = self._user_tasks(user_id)
            if not tasks:
                return 0.0
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def get_average_completion_time(self, user_id) -> Optional[float]:
        with self._lock:
            self._require_user(user_id)
            times = [
                s
                for s in (self._completion_seconds(t) for t in self._user_tasks(user_id))
                if s is not None
            ]
            if not times:
                return None
            return sum(times) / len(times)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None) -> Rating:
        with self._lock:
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if task_id is not None:
                self._require_task(task_id)
            if rater_id == ratee_id:
                raise ConflictError("users cannot rate themselves")

            rating = Rating(
                id=self._state.next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._state.now(),
            )
            self._state.ratings[rating.id] = rating
            self._state.ratings_by_ratee.setdefault(ratee_id, set()).add(rating.id)
            return _clone(rating)

    def _ratings_for(self, user_id) -> List[Rating]:
        ids = sorted(self._state.ratings_by_ratee.get(user_id, set()))
        return [self._state.ratings[i] for i in ids]

    def get_ratings_summary(self, user_id) -> dict:
        with self._lock:
            self._require_user(user_id)
            ratings = self._ratings_for(user_id)
            count = len(ratings)
            average = sum(r.score for r in ratings) / count if count else 0.0
            return {
                "count": count,
                "average": average,
                "ratings": _clone_list(ratings),
            }

    def get_user_dashboard(self, user_id) -> dict:
        with self._lock:
            self._require_user(user_id)
            tasks = self._user_tasks(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            completion_rate = completed / total if total else 0.0

            times = [
                s
                for s in (self._completion_seconds(t) for t in tasks)
                if s is not None
            ]
            average_completion_time = sum(times) / len(times) if times else None

            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count if rating_count else 0.0
            )

            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": average_completion_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }


