# Reporting
# ---------------------------------------------------------------------------
class ReportManager(_BaseManager):
    @staticmethod
    def _completion_seconds(task: Task) -> Optional[float]:
        if (
            task.status == TaskStatus.COMPLETED
            and task.started_at is not None
            and task.completed_at is not None
        ):
            return (task.completed_at - task.started_at).total_seconds()
        return None

    def project_progress_report(self, project_id) -> dict:
        with self._lock:
            self._require_project(project_id)
            ids = self._state.tasks_by_project.get(project_id, set())
            tasks = [self._state.tasks[i] for i in ids if i in self._state.tasks]
            now = self._state.now()

            status_counts = {s.value: 0 for s in TaskStatus}
            overdue = 0
            per_assignee: Dict[int, dict] = {}
            completed = 0
            for task in tasks:
                status_counts[task.status.value] += 1
                if task.status == TaskStatus.COMPLETED:
                    completed += 1
                if (
                    task.deadline is not None
                    and task.deadline < now
                    and task.status != TaskStatus.COMPLETED
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id, {"total": 0, "completed": 0}
                    )
                    bucket["total"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed"] += 1

            total = len(tasks)
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": (completed / total) if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None) -> dict:
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                tasks = [
                    t for t in self._state.tasks.values() if t.project_id == project_id
                ]
            else:
                tasks = list(self._state.tasks.values())

            user_ids = sorted(
                {t.assignee_id for t in tasks if t.assignee_id is not None}
            )
            rows = []
            for uid in user_ids:
                user_tasks = [t for t in tasks if t.assignee_id == uid]
                total = len(user_tasks)
                completed = sum(
                    1 for t in user_tasks if t.status == TaskStatus.COMPLETED
                )
                times = [
                    s
                    for s in (self._completion_seconds(t) for t in user_tasks)
                    if s is not None
                ]
                rows.append(
                    {
                        "user_id": uid,
                        "total_tasks": total,
                        "completed_tasks": completed,
                        "completion_rate": (completed / total) if total else 0.0,
                        "average_completion_time": (
                            sum(times) / len(times) if times else None
                        ),
                    }
                )
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id) -> dict:
        with self._lock:
            self._require_user(user_id)
            ids = sorted(self._state.tasks_by_assignee.get(user_id, set()))
            tasks = [self._state.tasks[i] for i in ids if i in self._state.tasks]
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            times = [
                s
                for s in (self._completion_seconds(t) for t in tasks)
                if s is not None
            ]
            task_rows = [
                {
                    "task_id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "project_id": t.project_id,
                    "completed_at": t.completed_at.isoformat()
                    if t.completed_at is not None
                    else None,
                }
                for t in tasks
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": (
                    sum(times) / len(times) if times else None
                ),
                "tasks": task_rows,
            }

    # -- export -----------------------------------------------------------
    def export_report(self, report, report_format):
        if not isinstance(report_format, ReportFormat):
            raise ValidationError("report_format must be a ReportFormat")
        if not isinstance(report, dict):
            raise ValidationError("report must be a mapping")
        if report_format == ReportFormat.CSV:
            return self._to_csv(report)
        return self._to_pdf(report)

    @staticmethod
    def _to_csv(report: dict) -> str:
        out = io.StringIO()
        writer = csv.writer(out)
        rows = report.get("rows")
        if isinstance(rows, list):
            if rows:
                columns = list(rows[0].keys())
            else:
                columns = [
                    "user_id",
                    "total_tasks",
                    "completed_tasks",
                    "completion_rate",
                    "average_completion_time",
                ]
            writer.writerow(columns)
            for row in rows:
                writer.writerow([row.get(col, "") for col in columns])
        else:
            writer.writerow(["field", "value"])
            for key, value in report.items():
                writer.writerow([key, value])
        return out.getvalue()

    def _to_pdf(self, report: dict) -> bytes:
        return _build_pdf(self._report_lines(report))

    @staticmethod
    def _report_lines(report: dict) -> List[str]:
        lines = ["Report: {0}".format(report.get("report_type", "report"))]
        rows = report.get("rows")
        if isinstance(rows, list):
            for row in rows:
                lines.append(
                    ", ".join("{0}={1}".format(k, v) for k, v in row.items())
                )
        else:
            for key, value in report.items():
                if key == "report_type":
                    continue
                lines.append("{0}: {1}".format(key, value))
        if len(lines) == 1:
            lines.append("(no data)")
        return lines


def _build_pdf(lines: List[str]) -> bytes:
    """Build a minimal, structurally valid single-page PDF document."""
    content_parts = [b"BT", b"/F1 12 Tf", b"72 720 Td", b"14 TL"]
    first = True
    for line in lines:
        safe = (
            str(line)
            .replace("\\", "\\\\")
            .replace("(", "\\(")
            .replace(")", "\\)")
        )
        encoded = safe.encode("ascii", "replace")
        if first:
            content_parts.append(b"(" + encoded + b") Tj")
            first = False
        else:
            content_parts.append(b"T*")
            content_parts.append(b"(" + encoded + b") Tj")
    content_parts.append(b"ET")
    stream = b"\n".join(content_parts)

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
        b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>",
        b"<< /Length " + str(len(stream)).encode("ascii") + b" >>\nstream\n"
        + stream
        + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    out = bytearray()
    out += b"%PDF-1.4\n"
    offsets = []
    for index, body in enumerate(objects, start=1):
        offsets.append(len(out))
        out += str(index).encode("ascii") + b" 0 obj\n" + body + b"\nendobj\n"

    xref_pos = len(out)
    size = len(objects) + 1
    out += b"xref\n0 " + str(size).encode("ascii") + b"\n"
    out += b"0000000000 65535 f \n"
    for offset in offsets:
        out += ("%010d 00000 n \n" % offset).encode("ascii")
    out += b"trailer\n<< /Size " + str(size).encode("ascii") + b" /Root 1 0 R >>\n"
    out += b"startxref\n" + str(xref_pos).encode("ascii") + b"\n%%EOF\n"
    return bytes(out)


